import{_ as e,c as s,S as t,o as n}from"./chunks/framework.BjmDYXuv.js";const g=JSON.parse('{"title":"HuggingFace Spaces","description":"","frontmatter":{},"headers":[],"relativePath":"spaces/overview.md","filePath":"spaces/overview.md","lastUpdated":1776166453000}'),i={name:"spaces/overview.md"};function l(p,a,o,r,c,d){return n(),s("div",null,a[0]||(a[0]=[t(`<h1 id="huggingface-spaces" tabindex="-1">HuggingFace Spaces <a class="header-anchor" href="#huggingface-spaces" aria-label="Permalink to &quot;HuggingFace Spaces&quot;">​</a></h1><p>ColliderML ships four public HuggingFace Spaces, each a lightweight Gradio frontend for a different slice of the platform. The code lives under <a href="https://github.com/OpenDataDetector/ColliderML/tree/main/spaces" target="_blank" rel="noreferrer"><code>spaces/</code></a> in this repository and is auto-synced to HuggingFace on every push to <code>main</code> (staging previews sync on every push to <code>staging</code>) via the <code>sync-spaces.yml</code> workflow.</p><h2 id="the-four-spaces" tabindex="-1">The four Spaces <a class="header-anchor" href="#the-four-spaces" aria-label="Permalink to &quot;The four Spaces&quot;">​</a></h2><table><thead><tr><th style="text-align:left;">Space</th><th style="text-align:left;">What it does</th><th style="text-align:left;">Needs login?</th></tr></thead><tbody><tr><td style="text-align:left;"><a href="./event-display.html">Event Display</a></td><td style="text-align:left;">Interactive 3D viewer for single events</td><td style="text-align:left;">No</td></tr><tr><td style="text-align:left;"><a href="./simulation-form.html">Simulation Form</a></td><td style="text-align:left;">Submit custom simulations via form or chat agent</td><td style="text-align:left;">HuggingFace OAuth</td></tr><tr><td style="text-align:left;"><a href="./leaderboard.html">Leaderboard</a></td><td style="text-align:left;">Browse + submit to benchmark task leaderboards</td><td style="text-align:left;">HuggingFace OAuth for submission</td></tr><tr><td style="text-align:left;"><a href="./model-zoo.html">Model Zoo</a></td><td style="text-align:left;">Browse HF models tagged <code>colliderml</code></td><td style="text-align:left;">No</td></tr></tbody></table><p>A fifth Space — <code>colliderml-admin</code> — is <strong>private</strong> and lives in the <a href="https://github.com/OpenDataDetector/colliderml-production" target="_blank" rel="noreferrer"><code>colliderml-production</code></a> repository instead. It exposes operator controls (credit grants, user bans, kill switch) and is gated behind a separate admin token.</p><h2 id="how-the-spaces-fit-the-platform" tabindex="-1">How the Spaces fit the platform <a class="header-anchor" href="#how-the-spaces-fit-the-platform" aria-label="Permalink to &quot;How the Spaces fit the platform&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>┌──────────────────────┐         ┌──────────────────────┐</span></span>
<span class="line"><span>│  colliderml pip pkg  │         │  HuggingFace Spaces  │</span></span>
<span class="line"><span>│  (this repo)         │         │  (this repo, synced) │</span></span>
<span class="line"><span>└──────────┬───────────┘         └──────────┬───────────┘</span></span>
<span class="line"><span>           │                                │</span></span>
<span class="line"><span>           │                                │  HF OAuth → bearer token</span></span>
<span class="line"><span>           │                                │</span></span>
<span class="line"><span>           ▼                                ▼</span></span>
<span class="line"><span>       ┌──────────────────────────────────────┐</span></span>
<span class="line"><span>       │   ColliderML Backend (FastAPI)       │</span></span>
<span class="line"><span>       │   (colliderml-production repo)       │</span></span>
<span class="line"><span>       │                                      │</span></span>
<span class="line"><span>       │   POST /v1/simulate                  │</span></span>
<span class="line"><span>       │   GET  /v1/me, /v1/requests/{id}     │</span></span>
<span class="line"><span>       │   POST /v1/benchmark/{task}/submit   │</span></span>
<span class="line"><span>       │   GET  /v1/leaderboard/{task}        │</span></span>
<span class="line"><span>       └──────────────────┬───────────────────┘</span></span>
<span class="line"><span>                          │</span></span>
<span class="line"><span>                          ▼</span></span>
<span class="line"><span>                ┌─────────────────┐</span></span>
<span class="line"><span>                │  NERSC SFAPI    │</span></span>
<span class="line"><span>                │  Perlmutter     │</span></span>
<span class="line"><span>                └─────────────────┘</span></span></code></pre></div><p>The Spaces <strong>never talk to NERSC directly</strong> — every button in every Space is a thin wrapper around a backend HTTP endpoint. The backend does all the authentication, quota enforcement, credit accounting, and actual SFAPI dispatch.</p><p>This means the same features are available whether you reach for the pip package or a Space: <code>colliderml simulate --remote</code> and the Simulation Form Space both POST to <code>/v1/simulate</code>; <code>colliderml.tasks.submit</code> and the Leaderboard Space both POST to <code>/v1/benchmark/&lt;task&gt;/submit</code>.</p><h2 id="embedding-a-space-in-your-own-site" tabindex="-1">Embedding a Space in your own site <a class="header-anchor" href="#embedding-a-space-in-your-own-site" aria-label="Permalink to &quot;Embedding a Space in your own site&quot;">​</a></h2><p>HuggingFace Spaces have a built-in iframe embed:</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">iframe</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://huggingface.co/spaces/CERN/colliderml-event-display&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    frameborder</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    width</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;850&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    height</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;450&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">iframe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>The four public Spaces carry <code>hf_oauth: true</code> where needed and an Apache-2.0 license, so they&#39;re safe to embed in papers, blog posts, or lab pages. Please keep the attribution link visible.</p><h2 id="running-a-space-locally" tabindex="-1">Running a Space locally <a class="header-anchor" href="#running-a-space-locally" aria-label="Permalink to &quot;Running a Space locally&quot;">​</a></h2><p>Each Space is a self-contained Gradio app:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> spaces/event-display</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install -r requirements.txt</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app.py</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Open http://localhost:7860</span></span></code></pre></div><p>For Spaces that need backend auth (<code>simulation-form</code>, <code>leaderboard</code>), set <code>COLLIDERML_BACKEND=http://localhost:8000</code> to point at a local backend checkout, and supply a HuggingFace token via env var instead of OAuth.</p><h2 id="deployment-workflow" tabindex="-1">Deployment workflow <a class="header-anchor" href="#deployment-workflow" aria-label="Permalink to &quot;Deployment workflow&quot;">​</a></h2><p><code>.github/workflows/sync-spaces.yml</code> (landing in commit B7 of the v0.4.0 migration) matrix-builds every directory under <code>spaces/</code> and pushes it to the corresponding HuggingFace Space via <code>huggingface_hub.upload_folder</code>. On <code>staging</code> pushes the Spaces are synced to suffixed variants (<code>-staging</code>) so you can preview changes without clobbering the production Space.</p><p>See the individual Space pages for each one&#39;s specifics.</p>`,20)]))}const u=e(i,[["render",l]]);export{g as __pageData,u as default};
